public class InheritanceBasics {

    static class Animal {
        String name;
        int age;

        Animal(String name, int age) {
            this.name = name;
            this.age  = age;
        }

        void eat() {
            System.out.println(name + " is eating");
        }

        void sleep() {
            System.out.println(name + " is sleeping");
        }

        @Override
        public String toString() {
            return getClass().getSimpleName() + "[" + name + ", age=" + age + "]";
        }
    }

    // Dog IS-A Animal — inherits name, age, eat(), sleep()
    static class Dog extends Animal {
        String breed;

        Dog(String name, int age, String breed) {
            super(name, age);   // MUST call parent constructor first
            this.breed = breed;
        }

        void bark() {           // new method unique to Dog
            System.out.println(name + " says: Woof!");
        }

        @Override
        public String toString() {
            return super.toString() + " breed=" + breed;
        }
    }

    // GuideDog IS-A Dog IS-A Animal — three-level chain
    static class GuideDog extends Dog {
        String owner;

        GuideDog(String name, int age, String breed, String owner) {
            super(name, age, breed);
            this.owner = owner;
        }

        void guide() {
            System.out.println(name + " guides " + owner);
        }
    }

    public static void main(String[] args) {
        Dog d = new Dog("Rex", 3, "Labrador");
        d.eat();    // inherited from Animal
        d.sleep();  // inherited from Animal
        d.bark();   // Dog's own method
        System.out.println(d); // Dog[Rex, age=3] breed=Labrador

        GuideDog g = new GuideDog("Buddy", 5, "Golden", "John");
        g.eat();    // inherited from Animal (2 levels up)
        g.bark();   // inherited from Dog
        g.guide();  // GuideDog's own method
    }
}

public class MethodOverriding {

    static class Shape {
        String color;

        Shape(String color) { this.color = color; }

        double area() {
            return 0; // default — subclasses should override
        }

        String describe() {
            return color + " shape, area=" + String.format("%.2f", area());
        }
    }

    static class Circle extends Shape {
        double radius;

        Circle(double radius, String color) {
            super(color);         // call Shape(color)
            this.radius = radius;
        }

        @Override               // tells compiler we intend to override
        double area() {
            return Math.PI * radius * radius;
        }

        @Override
        String describe() {
            return super.describe() + " (circle r=" + radius + ")";
            // super.describe() calls Shape.describe() which calls THIS.area() — polymorphic!
        }
    }

    static class Rectangle extends Shape {
        double w, h;

        Rectangle(double w, double h, String color) {
            super(color); this.w = w; this.h = h;
        }

        @Override
        double area() { return w * h; }

        @Override
        String describe() {
            return super.describe() + " (rect " + w + "x" + h + ")";
        }
    }

    public static void main(String[] args) {
        Shape s  = new Shape("grey");
        Circle c = new Circle(5, "red");
        Rectangle r = new Rectangle(4, 6, "blue");

        System.out.println(s.describe());  // grey shape, area=0.00
        System.out.println(c.describe());  // red shape, area=78.54 (circle r=5.0)
        System.out.println(r.describe());  // blue shape, area=24.00 (rect 4.0x6.0)
    }
}

public class SuperDemo {

    static class Vehicle {
        String make;
        int year;
        double fuelLevel;

        Vehicle(String make, int year) {
            this.make = make;
            this.year = year;
            this.fuelLevel = 100.0;
        }

        String status() {
            return make + " (" + year + ") fuel=" + fuelLevel + "%";
        }

        void refuel(double amount) {
            fuelLevel = Math.min(100, fuelLevel + amount);
            System.out.println(make + " refuelled to " + fuelLevel + "%");
        }
    }

    static class ElectricCar extends Vehicle {
        double batteryLevel;

        ElectricCar(String make, int year) {
            super(make, year);        // Vehicle constructor
            this.fuelLevel = 0;       // no fuel tank
            this.batteryLevel = 100.0;
        }

        @Override
        String status() {
            return super.status()    // Vehicle.status() as a base
                + " | battery=" + batteryLevel + "%";
        }

        @Override
        void refuel(double amount) {
            // super.refuel(amount); // would set fuelLevel — NOT what we want
            batteryLevel = Math.min(100, batteryLevel + amount);
            System.out.println(make + " charged to " + batteryLevel + "%");
        }

        void chargeFast() {
            refuel(50);  // calls THIS class's refuel() — not super's
        }
    }

    public static void main(String[] args) {
        ElectricCar tesla = new ElectricCar("Tesla", 2023);
        tesla.batteryLevel = 30;

        System.out.println(tesla.status());
        // Tesla (2023) fuel=0.0% | battery=30.0%

        tesla.refuel(40);   // ElectricCar.refuel() — charges battery
        tesla.chargeFast(); // calls refuel(50) — also ElectricCar's
    }
}

import java.util.Objects;

public class ObjectClassDemo {

    // Every class implicitly extends Object
    // Object provides: equals, hashCode, toString, getClass, clone, wait, notify, finalize

    static class Point {
        int x, y;
        Point(int x, int y) { this.x=x; this.y=y; }

        // WITHOUT overrides — Object defaults:
        // toString()  → "Point@1b6d3586" (class + identity hashcode)
        // equals(o)   → reference comparison (==)
        // hashCode()  → identity-based number
    }

    static class BetterPoint {
        int x, y;
        BetterPoint(int x, int y) { this.x=x; this.y=y; }

        @Override public String toString() { return "(" + x + "," + y + ")"; }
        @Override public boolean equals(Object o) {
            if (!(o instanceof BetterPoint p)) return false;
            return x == p.x && y == p.y;
        }
        @Override public int hashCode() { return Objects.hash(x, y); }
    }

    public static void main(String[] args) {
        Point p1 = new Point(3, 4);
        Point p2 = new Point(3, 4);

        // Object defaults
        System.out.println(p1.toString());      // Point@<hex> — useless!
        System.out.println(p1.equals(p2));      // false — reference compare
        System.out.println(p1.getClass().getSimpleName()); // Point

        // All objects can be assigned to Object reference
        Object o = p1;                          // widening — always safe
        System.out.println(o instanceof Point); // true

        BetterPoint b1 = new BetterPoint(3, 4);
        BetterPoint b2 = new BetterPoint(3, 4);
        System.out.println(b1.toString());  // (3,4)
        System.out.println(b1.equals(b2));  // true
        System.out.println(b1.hashCode() == b2.hashCode()); // true
    }
}

public class DispatchDemo {

    static class A {
        A() { System.out.println("A constructor"); show(); }
        void show() { System.out.println("A.show()"); }
    }

    static class B extends A {
        int value = 42;
        B() { super(); System.out.println("B constructor"); }
        @Override
        void show() { System.out.println("B.show() value=" + value); }
    }

    static class C extends B {
        C() { super(); System.out.println("C constructor"); }
        @Override
        void show() { System.out.println("C.show()"); }
    }

    // Demonstrates constructor order and the DANGER of calling
    // overridable methods in constructors
    public static void main(String[] args) {
        System.out.println("--- new B() ---");
        B b = new B();
        // Output:
        // A constructor
        // B.show() value=0   ← DANGER: B.value not yet initialized when A() calls show()!
        // B constructor

        System.out.println("--- new C() ---");
        C c = new C();
        // A constructor → C.show() (polymorphic!) → B constructor → C constructor
        System.out.println("---");
        c.show(); // C.show()

        // Polymorphic reference
        A ref = c;
        ref.show(); // C.show() — runtime dispatch to actual type
    }
}

