public class Q3 {
    static class Logger {
        void log(String msg) {
            System.out.println("[LOG] " + msg);
        }
    }

    static class TimestampLogger extends Logger {
        private long counter = 0;
        @Override
        void log(String msg) {
            String timestamped = "[ts=" + (++counter) + "] " + msg;
