public class Q4 {
    static class Animal {}
    static class Dog extends Animal {}
    static class GoldenRetriever extends Dog {}

    public static String checkInstanceOf(Object obj) {
        StringBuilder sb = new StringBuilder();
        if (obj instanceof GoldenRetriever) sb.append("GoldenRetriever ");
        if (obj instanceof Dog)             sb.append("Dog ");
        if (obj instanceof Animal)          sb.append("Animal ");
        if (obj instanceof Object)          sb.append("Object");
        return sb.toString().trim();
    }

    public static void main(String[] args) {
        System.out.println(checkInstanceOf(new GoldenRetriever()));
        // GoldenRetriever Dog Animal Object
        System.out.println(checkInstanceOf(new Dog()));
        // Dog Animal Object
        System.out.println(checkInstanceOf(new Animal()));
        // Animal Object
    }
}

