import java.util.Objects;

public class Q9 {
    static class Person {
        String name; int age;
        Person(String name, int age) { this.name=name; this.age=age; }
        @Override public boolean equals(Object o) {
            if (!(o instanceof Person p)) return false;
            return Objects.equals(name, p.name) && age == p.age;
        }
        @Override public int hashCode() { return Objects.hash(name, age); }
    }

    static class Employee extends Person {
        String employeeId;
        Employee(String name, int age, String eid) { super(name, age); employeeId=eid; }
        @Override public boolean equals(Object o) {
            if (!super.equals(o)) return false;          // Person fields must match
            if (!(o instanceof Employee e)) return false; // must be Employee
            return Objects.equals(employeeId, e.employeeId);
        }
        @Override public int hashCode() {
            return Objects.hash(super.hashCode(), employeeId);
        }
    }

    public static void main(String[] args) {
        Employee e1 = new Employee("Alice", 30, "E001");
        Employee e2 = new Employee("Alice", 30, "E001");
        Employee e3 = new Employee("Alice", 30, "E002");
        System.out.println(e1.equals(e2)); // true
        System.out.println(e1.equals(e3)); // false
    }
}

