public class Q14 {
    sealed interface Shape permits Circle, Rectangle, Triangle {}
    record Circle(double r) implements Shape {}
    record Rectangle(double w, double h) implements Shape {}
    record Triangle(double b, double h) implements Shape {}

    public static double area(Shape shape) {
        return switch (shape) {
            case Circle c    -> Math.PI * c.r() * c.r();
            case Rectangle r -> r.w() * r.h();
            case Triangle t  -> 0.5 * t.b() * t.h();
        }; // exhaustive — compiler verifies all cases covered
    }

    public static void main(String[] args) {
        System.out.printf("%.2f%n", area(new Circle(5)));       // 78.54
        System.out.printf("%.2f%n", area(new Rectangle(4, 6))); // 24.00
        System.out.printf("%.2f%n", area(new Triangle(3, 8)));  // 12.00
    }
}

