public class Q16 {
    // BAD: overridable method calls overridable method
    static class Counter {
        int count = 0;
        void increment() { incrementBy(1); } // polymorphic dispatch!
        void incrementBy(int n) { count += n; }
    }

    static class LoggingCounter extends Counter {
        int logCount = 0;
        @Override void incrementBy(int n) {
            logCount++;
            super.incrementBy(n);
        }
    }

    // FIXED: increment() uses private helper
    static class SafeCounter {
        int count = 0;
        void increment() { addToCount(1); }   // private — not overridable
        void incrementBy(int n) { addToCount(n); }
        private void addToCount(int n) { count += n; }
    }

    static class SafeLoggingCounter extends SafeCounter {
        int logCount = 0;
        @Override void incrementBy(int n) {
            logCount++;
            super.incrementBy(n);
        }
    }

    public static void main(String[] args) {
        LoggingCounter lc = new LoggingCounter();
        lc.increment();
        lc.increment();
        lc.incrementBy(5);
        System.out.println("count=" + lc.count);       // 7
        System.out.println("logCount=" + lc.logCount); // 3

        SafeLoggingCounter sc = new SafeLoggingCounter();
        sc.increment();
        sc.increment();
        sc.incrementBy(5);
        System.out.println("safe count=" + sc.count);       // 7
        System.out.println("safe logCount=" + sc.logCount); // 1 (only incrementBy(5) logged)
    }
}

