import java.util.*;

public class Q20 {
    // INHERITANCE (rigid — need a new class for every combination)
    static class Vehicle  { String type = "Vehicle"; }
    static class Car extends Vehicle { Car(){type="Car";} }
    static class SportsCar extends Car { SportsCar(){type="SportsCar";} }
    static class TurboSportsCar extends SportsCar { TurboSportsCar(){type="TurboSportsCar";} }

    // COMPOSITION (flexible — mix components freely)
    interface Component { String describe(); }
    static class Engine   implements Component { public String describe() { return "Engine"; } }
    static class Spoiler  implements Component { public String describe() { return "Spoiler"; } }
    static class TurboKit implements Component { public String describe() { return "Turbo"; } }

    static class FlexCar {
        List<Component> components;
        FlexCar(Component... parts) { components = Arrays.asList(parts); }
        String describe() {
            StringBuilder sb = new StringBuilder("Car[");
            for (Component c : components) sb.append(c.describe()).append(" ");
            return sb.toString().trim() + "]";
        }
    }

    public static void main(String[] args) {
        System.out.println(new TurboSportsCar().type); // TurboSportsCar

        FlexCar turboSports = new FlexCar(new Engine(), new Spoiler(), new TurboKit());
        FlexCar ecoCommuter  = new FlexCar(new Engine());
        FlexCar spoilerNinja = new FlexCar(new Engine(), new Spoiler());

        System.out.println(turboSports.describe()); // Car[Engine Spoiler Turbo]
        System.out.println(ecoCommuter.describe());  // Car[Engine]
        System.out.println(spoilerNinja.describe()); // Car[Engine Spoiler]
    }
}
